import type { Currency } from "../lib/money";
import type { Region } from "../lib/region";

export type SubscriptionStatus = "trialing" | "active" | "past_due" | "canceled";

export type Subscription = {
  id: string;
  accountId: string;
  plan: "free" | "team" | "enterprise";
  status: SubscriptionStatus;
  currentPeriodEnd: string;
  cancelAtPeriodEnd: boolean;
  region: Region;
};

export type Invoice = {
  id: string;
  accountId: string;
  subscriptionId: string;
  amountCents: number;
  currency: Currency;
  region: Region;
  status: "open" | "paid" | "void" | "refunded";
  createdAt: string;
};

export type Refund = {
  id: string;
  invoiceId: string;
  amountCents: number;
  currency: Currency;
  region: Region;
  createdAt: string;
};

import type { Invoice, Refund, Subscription } from "./types";

const subscriptions = new Map<string, Subscription>();
const invoices = new Map<string, Invoice>();
const refunds = new Map<string, Refund>();

export const db = {
  subscriptions,
  invoices,
  refunds,
  async transaction<T>(fn: () => Promise<T>): Promise<T> {
    return fn();
  },
};

import { readEnv } from "./env";

export type LedgerWriteMode = "legacy" | "dual" | "ledger";
export type LedgerReadMode = "legacy" | "ledger";

export function getLedgerWriteMode(): LedgerWriteMode {
  const mode = readEnv("BILLING_LEDGER_WRITE_MODE", "legacy");
  return mode === "dual" || mode === "ledger" ? mode : "legacy";
}

export function getLedgerReadMode(): LedgerReadMode {
  return readEnv("BILLING_LEDGER_READ_MODE", "legacy") === "ledger"
    ? "ledger"
    : "legacy";
}
export type Region = "us" | "eu" | "apac";

export function regionFromAccount(accountId: string): Region {
  if (accountId.startsWith("acct_eu_")) return "eu";
  if (accountId.startsWith("acct_apac_")) return "apac";
  return "us";
}
const processed = new Set<string>();

export async function markProcessedOnce(key: string): Promise<boolean> {
  if (processed.has(key)) return false;
  processed.add(key);
  return true;
}

import assert from "node:assert/strict";
