import { recordInvoicePaid } from "../../billing/invoiceService";
import type { Invoice } from "../../db/types";
import { markProcessedOnce } from "../../lib/idempotency";
import { regionFromAccount } from "../../lib/region";

export type StripeInvoicePaidEvent = {
  id: string;
  type: "invoice.paid";
  accountId: string;
  invoiceId: string;
  subscriptionId: string;
  amountPaid: number;
  currency: "USD" | "EUR" | "JPY";
  customerEmail?: string;
  paymentMethod?: string;
  createdAt: string;
};

export async function handleStripeWebhook(event: StripeInvoicePaidEvent) {
  const firstSeen = await markProcessedOnce(`stripe:${event.id}`);
  if (!firstSeen) return { ok: true, duplicate: true };

  const invoice: Invoice = {
    id: event.invoiceId,
    accountId: event.accountId,
    subscriptionId: event.subscriptionId,
    amountCents: event.amountPaid,
    currency: event.currency,
    region: regionFromAccount(event.accountId),
    status: "paid",
    createdAt: event.createdAt,
  };

  await recordInvoicePaid(invoice);
  return { ok: true };
}

import { db } from "../db/client";
import type { Invoice } from "../db/types";
import { assertCents } from "../lib/money";

export async function recordInvoicePaid(invoice: Invoice) {
  assertCents(invoice.amountCents);
  db.invoices.set(invoice.id, { ...invoice, status: "paid" });
  return db.invoices.get(invoice.id)!;
}

export async function listInvoicesForExport() {
  return [...db.invoices.values()].sort((a, b) => a.createdAt.localeCompare(b.createdAt));
}
import { db } from "../db/client";
import type { Refund } from "../db/types";
import { assertCents } from "../lib/money";

export async function recordRefund(refund: Refund) {
  assertCents(refund.amountCents);
  db.refunds.set(refund.id, refund);
  const invoice = db.invoices.get(refund.invoiceId);
  if (invoice) db.invoices.set(invoice.id, { ...invoice, status: "refunded" });
  return refund;
}
import { db } from "../db/client";

export async function getSubscriptionResponse(accountId: string) {
  const subscription = db.subscriptions.get(accountId);
  if (!subscription) {
    return {
      plan: "free",
      status: "active",
      currentPeriodEnd: null,
      cancelAtPeriodEnd: false,
    };
  }
  return {
    plan: subscription.plan,
    status: subscription.status,
    currentPeriodEnd: subscription.currentPeriodEnd,
    cancelAtPeriodEnd: subscription.cancelAtPeriodEnd,
  };
}

import { recordRefund } from "../billing/refundService";
import type { Refund } from "../db/types";

export async function postRefundApi(refund: Refund) {
  const result = await recordRefund(refund);
  return { ok: true, refundId: result.id };
}
import { listInvoicesForExport } from "../billing/invoiceService";

export async function getInvoiceExportApi() {
  const invoices = await listInvoicesForExport();
  return {
    rows: invoices.map((invoice) => ({
      invoiceId: invoice.id,
      amountCents: invoice.amountCents,
      currency: invoice.currency,
      status: invoice.status,
      createdAt: invoice.createdAt,
    })),
  };
}
import { listInvoicesForExport } from "../billing/invoiceService";

export async function reconcileStripe() {
  const invoices = await listInvoicesForExport();
  return {
    invoiceCount: invoices.length,
    totalCents: invoices.reduce((sum, invoice) => sum + invoice.amountCents, 0),
  };
}

